SELECT COUNT(*) AS debate_count
FROM debates
WHERE debate_date = '01-01-2023';

SELECT session_number, titles
FROM debates
ORDER BY session_number ASC;

SELECT titles
FROM debates
WHERE debate_date = '15-10-2023';

SELECT debate_date, COUNT(*) AS debate_count
FROM debates
GROUP BY debate_date;

SELECT debate_type_id, COUNT(*) AS debate_count
FROM debates
GROUP BY debate_type_id;

SELECT titles
FROM debates
WHERE debate_type_id = (SELECT type_id FROM debate_types WHERE type_name = 'General Debate');
